426 /// A wrapper class for std::optional<APInt> that provides arithmetic operators
427 /// with overflow checking in a signed sense. This allows us to omit inserting
428 /// an overflow check at every arithmetic operation, which simplifies the code
429 /// if the operations are chained like `a + b + c + ...`.
430 ///
431 /// If an calculation overflows, the result becomes "invalid" which is
432 /// internally represented by std::nullopt. If any operand of an arithmetic
433 /// operation is "invalid", the result will also be "invalid".
434 struct OverflowSafeSignedAPInt {
435   OverflowSafeSignedAPInt() : Value(std::nullopt) {}
436   OverflowSafeSignedAPInt(const APInt &V) : Value(V) {}
437   OverflowSafeSignedAPInt(const std::optional<APInt> &V) : Value(V) {}
438 
439   OverflowSafeSignedAPInt operator+(const OverflowSafeSignedAPInt &RHS) const {
440     if (!Value || !RHS.Value)
441       return OverflowSafeSignedAPInt();
442     bool Overflow;
443     APInt Result = Value->sadd_ov(*RHS.Value, Overflow);
444     if (Overflow)
445       return OverflowSafeSignedAPInt();
446     return OverflowSafeSignedAPInt(Result);
447   }
448 
449   OverflowSafeSignedAPInt operator+(int RHS) const {
450     if (!Value)
451       return OverflowSafeSignedAPInt();
452     return *this + fromInt(RHS);
453   }
454 
455   OverflowSafeSignedAPInt operator-(const OverflowSafeSignedAPInt &RHS) const {
456     if (!Value || !RHS.Value)
457       return OverflowSafeSignedAPInt();
458     bool Overflow;
459     APInt Result = Value->ssub_ov(*RHS.Value, Overflow);
460     if (Overflow)
461       return OverflowSafeSignedAPInt();
462     return OverflowSafeSignedAPInt(Result);
463   }
464 
465   OverflowSafeSignedAPInt operator-(int RHS) const {
466     if (!Value)
467       return OverflowSafeSignedAPInt();
468     return *this - fromInt(RHS);
469   }
470 
471   OverflowSafeSignedAPInt operator*(const OverflowSafeSignedAPInt &RHS) const {
472     if (!Value || !RHS.Value)
473       return OverflowSafeSignedAPInt();
474     bool Overflow;
475     APInt Result = Value->smul_ov(*RHS.Value, Overflow);
476     if (Overflow)
477       return OverflowSafeSignedAPInt();
478     return OverflowSafeSignedAPInt(Result);
479   }
480 
481   OverflowSafeSignedAPInt operator-() const {
482     if (!Value)
483       return OverflowSafeSignedAPInt();
484     if (Value->isMinSignedValue())
485       return OverflowSafeSignedAPInt();
486     return OverflowSafeSignedAPInt(-*Value);
487   }
488 
489   operator bool() const { return Value.has_value(); }
490 
491   bool operator!() const { return !Value.has_value(); }
492 
493   const APInt &operator*() const {
494     assert(Value && "Value is not available.");
495     return *Value;
496   }
497 
498   const APInt *operator->() const {
499     assert(Value && "Value is not available.");
500     return &*Value;
501   }
502 
503 private:
504   /// Underlying value. std::nullopt means "unknown". An arithmetic operation on
505   /// "unknown" always produces "unknown".
506   std::optional<APInt> Value;
507 
508   OverflowSafeSignedAPInt fromInt(uint64_t V) const {
509     assert(Value && "Value is not available.");
510     return OverflowSafeSignedAPInt(
511         APInt(Value->getBitWidth(), V, /*isSigned=*/true));
512   }
513 };
