 797 /// We only care about an affine AddRec at the moment. For an affine AddRec,
 798 /// the monotonicity can be inferred from its nowrap property. For example, let
 799 /// X and Y be loop-invariant, and assume Y is non-negative. An AddRec
 800 /// {X,+.Y}<nsw> implies:
 801 ///
 802 ///   X <=s (X + Y) <=s ((X + Y) + Y) <=s ...
 803 ///
 804 /// Thus, we can conclude that the AddRec is monotonically increasing with
 805 /// respect to the associated loop in a signed sense. The similar reasoning
 806 /// applies when Y is non-positive, leading to a monotonically decreasing
 807 /// AddRec.
 808 SCEVMonotonicity
 809 SCEVMonotonicityChecker::visitAddRecExprAux(const SCEVAddRecExpr *Expr) {
 810   // To update FoundInnermostLoop correctly, call visit on Start first.
 811   const SCEV *Start = Expr->getStart();
 812   SCEVMonotonicity StartMon = visit(Start);
 813   if (StartMon.isUnknown())
 814     return StartMon;
 815 
 816   if (!Expr->isAffine() || !Expr->hasNoSignedWrap())
 817     return createUnknown(Expr);
 818 
 819   const SCEV *Step = Expr->getStepRecurrence(*SE);
 820   const Loop *L = Expr->getLoop();
 821 
 822   if (!isLoopInvariant(Step))
 823     return createUnknown(Expr);
 824 
 825   switch (Domain) {
 826   case SCEVMonotonicityDomain::Entire:
 827     // If this is not the innermost loop, only checking nowrap is not enough.
 828     // Consider the following pseudo code:
 829     //
 830     //   for (int i = 0; i < INT32_MAX; i++)
 831     //     if (i < 42)
 832     //       for (int j = 0; j < 100; j++)
 833     //         A[i + j] = 0;
 834     //
 835     // In this case, the SCEV for the subscript expression `i + j` will have nsw
 836     // flags, but it is not monotonic over the entire domain. To handle
 837     // non-innermost loops, we need to check loop-guards. At the moment, simply
 838     // bail out if the loop is not innermost.
 839     if (FoundInnermostLoop)
 840       return createUnknown(Expr);
 841 
 842     // We also need to make sure that the loop has an exact backedge-taken
 843     // count.
 844     if (!SE->hasLoopInvariantBackedgeTakenCount(L))
 845       return createUnknown(Expr);
 846     break;
 847   case SCEVMonotonicityDomain::Effective:
 848     // Nothing to do for now.
 849     break;
 850   }
 851 
 852   return SCEVMonotonicity(SCEVMonotonicityType::MultivariateSignedMonotonic);
 853 }
