 939 // Returns NoAlias/MayAliass/MustAlias for two memory locations based upon their
 940 // underlaying objects. If LocA and LocB are known to not alias (for any reason:
 941 // tbaa, non-overlapping regions etc), then it is known there is no dependecy.
 942 // Otherwise the underlying objects are checked to see if they point to
 943 // different identifiable objects.
 944 static AliasResult underlyingObjectsAlias(AAResults *AA, const DataLayout &DL,
 945                                           const MemoryLocation &LocA,
 946                                           const MemoryLocation &LocB) {
 947   // Check the original locations (minus size) for noalias, which can happen for
 948   // tbaa, incompatible underlying object locations, etc.
 949   MemoryLocation LocAS =
 950       MemoryLocation::getBeforeOrAfter(LocA.Ptr, LocA.AATags);
 951   MemoryLocation LocBS =
 952       MemoryLocation::getBeforeOrAfter(LocB.Ptr, LocB.AATags);
 953   BatchAAResults BAA(*AA);
 954   BAA.enableCrossIterationMode();
 955 
 956   if (BAA.isNoAlias(LocAS, LocBS))
 957     return AliasResult::NoAlias;
 958 
 959   // Check the underlying objects are the same
 960   const Value *AObj = getUnderlyingObject(LocA.Ptr);
 961   const Value *BObj = getUnderlyingObject(LocB.Ptr);
 962 
 963   // If the underlying objects are the same, they must alias
 964   if (AObj == BObj)
 965     return AliasResult::MustAlias;
 966 
 967   // We may have hit the recursion limit for underlying objects, or have
 968   // underlying objects where we don't know they will alias.
 969   if (!isIdentifiedObject(AObj) || !isIdentifiedObject(BObj))
 970     return AliasResult::MayAlias;
 971 
 972   // Otherwise we know the objects are different and both identified objects so
 973   // must not alias.
 974   return AliasResult::NoAlias;
 975 }
